        lower.includes('card') ||
        lower.includes('pan') ||
        lower.includes('cvv') ||
        lower.includes('cvc') ||
        lower.includes('token') ||
        lower.includes('secret') ||
        lower.includes('account') ||
        lower.includes('iban') ||
        lower.includes('email') ||
        lower.includes('phone') ||
        lower.includes('name') ||
        lower.includes('address')
