export const usePayment = () => {
  const ctx = useContext(PaymentStateContext);
  if (!ctx) {
    throw new Error('usePayment must be used within a PaymentProvider');
  }
  return ctx;
};

export const usePaymentConfig = () => {
  return useContext(PaymentConfigContext);
};

export const PaymentButton = ({
  type = 'wallet',
  title,
  productId,
  amount,
  currency,
  merchantId,
  countryCode = 'US',
  label = 'Purchase',
  onSuccess,
  onError,
  disabled,
  style,
  textStyle,
}) => {
  const {
    busy,
    capabilities,
    purchaseProduct,
    createWalletPayment,
    presentWalletSheet,
  } = usePayment();

  const handlePress = useCallback(async () => {
    try {
      if (type === 'iap') {
        const result = await purchaseProduct({ productId });
        onSuccess?.(result);
        return;
      }

      const intent = await createWalletPayment({
        amount,
        currency,
        merchantId,
        label,
        countryCode,
      });

      const result = await presentWalletSheet({
        clientSecret: intent?.clientSecret,
        paymentIntentId: intent?.paymentIntentId,
        amount,
        currency,
        merchantId,
        label,
        countryCode,
      });

      onSuccess?.({
        intent,
        result,
      });
    } catch (error) {
      const normalized = normalizeError(error);
      onError?.(normalized);
      Alert.alert('Payment Failed', normalized.message);
    }
  }, [
    type,
    productId,
    amount,
    currency,
    merchantId,
    label,
    countryCode,
    purchaseProduct,
    createWalletPayment,
    presentWalletSheet,
    onSuccess,
    onError,
  ]);

  const isWalletSupported =
    Platform.OS === 'ios'
      ? !!capabilities?.wallets?.applePay
      : !!capabilities?.wallets?.googlePay;

  const isDisabled =
    !!disabled ||
    busy ||
    (type === 'iap' ? !productId : !isWalletSupported || !amount || !currency);

  const computedTitle =
    title ||
    (type === 'iap'
      ? 'Buy In-App Item'
      : Platform.OS === 'ios'
      ? 'Pay with Apple Pay'
      : 'Pay with Google Pay');

  return (
    <TouchableOpacity
      accessibilityRole="button"
      onPress={handlePress}
      disabled={isDisabled}
      style={[
        styles.button,
        type === 'iap' ? styles.iapButton : styles.walletButton,
        isDisabled && styles.buttonDisabled,
        style,
      ]}
    >
      {busy ? (
        <ActivityIndicator color="#fff" />
      ) : (
        <Text style={[styles.buttonText, textStyle]}>{computedTitle}</Text>
      )}
    </TouchableOpacity>
  );
};

export const PaymentStatus = () => {
  const { ready, available, busy, lastError, transactions, capabilities } = usePayment();

  return (
    <View style={styles.statusContainer}>
      <Text style={styles.statusTitle}>Payments</Text>
      <Text style={styles.statusText}>Ready: {String(ready)}</Text>
      <Text style={styles.statusText}>Available: {String(available)}</Text>
      <Text style={styles.statusText}>Busy: {String(busy)}</Text>
      <Text style={styles.statusText}>
        Wallet:
        {' '}
        {Platform.OS === 'ios'
          ? String(!!capabilities?.wallets?.applePay)
          : String(!!capabilities?.wallets?.googlePay)}
      </Text>
      <Text style={styles.statusText}>Transactions: {transactions.length}</Text>
      {lastError ? (
        <Text style={styles.errorText}>
          Error: {lastError.code} - {lastError.message}
        </Text>
      ) : null}
    </View>
  );
};

